import time

def pomodoro_timer(work_minutes=25, break_minutes=5, sessions=4):
    for i in range(sessions):
        print(f'\nPomodoro {i+1}/{sessions} — Focus time: {work_minutes} minutes')
        print('Work starts now. No distractions!')
        time.sleep(work_minutes * 60)
        if i < sessions - 1:
            print(f'Break time: {break_minutes} minutes')
            time.sleep(break_minutes * 60)
        else:
            print('Long break! Take 15–30 minutes.')

